head.script:
scwin.wrkLobranCd = "";
scwin.wrkLobranNm = "";
scwin.internalSellLodeptCd = "";
scwin.internalSellLodeptNm = "";
scwin.wrkLobranCdRow = 0;
scwin.vCurDate = "";
scwin.lobranCd = "";
scwin.lobranNm = "";
scwin.odrNo = "";
scwin.type = "";
scwin.userId = "";
scwin.hid_odrKndCd = "";
scwin.hid_ctrtClntNo = "";
scwin.hid_ctrtNo = "";
scwin.hid_realMchtclntNo = "";
scwin.hid_rowNo = "";
scwin.hid_chkUseFilter = "true";
scwin.hid_chkReterieve = "";
scwin.hid_modId = "";
scwin.hid_modDtm = "";
scwin.v_row = 0;
scwin.v_colid = "";

scwin.ODR_KND_CD_IMP_CVSSL_BULK_ODR = "";
scwin.ODR_KND_CD_IMP_GNRL_BULK_ODR = "";
scwin.ODR_KND_CD_EXP_CVSSL_BULK_ODR = "";
scwin.ODR_KND_CD_EXP_GNRL_BULK_ODR = "";
scwin.SELPCH_ITEM_CD_NOSELL = "";
scwin.TRANS_DEPARTMENT = "";
scwin.YN_YES = "";
scwin.YN_NO = "";
scwin.IMP_CD = "";
scwin.EXP_CD = "";
scwin.WRK_PL_CLS_CD_DOOR = "";
scwin.WRK_PL_CLS_CD_RGN = "";
scwin.WRK_PL_CLS_CD_PIER = "";
scwin.WRK_PL_CLS_CD_BERTH = "";
scwin.WRK_PL_CLS_CD_RAILSTN = "";
scwin.WRK_PL_CLS_CD_MARTRPIER = "";
scwin.WRK_STP_CD_CGSHF = "";
scwin.WRK_STP_CD_SHUTTLE = "";
scwin.WRK_STP_CD_GROUND_TRANS = "";
scwin.WRK_STP_CD_RAILROAD = "";
scwin.WRK_STP_CD_MARTR = "";
scwin.SELL_ITEM_CD_TRANS_RATE = "";
scwin.BIZ_DOM_CD_TRANS = "";
scwin.BIZ_DOM_CD_STV = "";
scwin.BIZ_DOM_CD_STR = "";

scwin.onpageload = function() {
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.lobranCd = $c.ses.getLobranCd();
    scwin.lobranNm = $c.ses.getLobranNm();
    scwin.userId = $c.ses.getUserId();
    scwin.wrkLobranCd = scwin.lobranCd;
    scwin.wrkLobranNm = scwin.lobranNm;

    scwin.params = $c.data.getParameter();
    if (scwin.params != null) {
        scwin.odrNo = scwin.params["odrNo"] || "";
        scwin.type = scwin.params["type"] || "";
    }

    // TODO: 서버 상수 조회 필요 - DsConstants, SdConstants 값을 서버에서 가져와 scwin 변수에 세팅
    // scwin.ODR_KND_CD_IMP_CVSSL_BULK_ODR, scwin.SELPCH_ITEM_CD_NOSELL 등

    scwin.f_defaultValue();

    if (scwin.odrNo != "") {
        lc_odrSearchGubun.setValue("1");
        ed_odrNo.setValue(scwin.odrNo);
        // TODO: lay_odrDt hide, lay_odrNo show - UI 가시성 제어
        scwin.f_Retrieve();
    }
};

scwin.onUdcCompleted = function() {
    udc_odrDt.setInitDate(scwin.vCurDate, scwin.vCurDate);
};

scwin.f_defaultValue = function() {
    lc_odrSearchGubun.setSelectedIndex(0);

    $c.gus.cfDisableObjects([btnInsertRow, btnDeleteRow, btnUndoMark, btnUpdate, btnSave]);

    dma_orderSearch.set("odrNo", "");
    dma_orderSearch.set("odrDtFrom", scwin.vCurDate);
    dma_orderSearch.set("odrDtTo", scwin.vCurDate);

    scwin.hid_ctrtClntNo = "";
    scwin.hid_ctrtNo = "";
    scwin.hid_realMchtclntNo = "";

    dma_lobranQueryCondition.set("lobranCd", scwin.lobranCd);
    dma_lobranQueryCondition.set("lobranClsCd", "T");
    if (scwin.wrkLobranCd == "4A5") {
        dma_lobranQueryCondition.set("deptmentCd", "5");
    } else {
        dma_lobranQueryCondition.set("deptmentCd", scwin.TRANS_DEPARTMENT);
    }
    dma_lobranQueryCondition.set("useYn", scwin.YN_YES);

    scwin.hid_chkUseFilter = "true";

    spa_totalRow.setValue(ds_odrCommWrkPath.getRowCount());
    spa_totalRow2.setValue(ds_odrWrkPathStepDetail.getRowCount());

    ed_odrNo.setFocus();
};

scwin.f_Retrieve = async function() {
    let searchGubun = lc_odrSearchGubun.getValue();

    if (searchGubun == "0") {
        let dtFrom = dma_orderSearch.get("odrDtFrom");
        let dtTo = dma_orderSearch.get("odrDtTo");
        if (!dtFrom || !dtTo) {
            let chk = await $c.gus.cfValidate([ed_odrDtFrom, ed_odrDtTo]);
            if (!chk) return;
        }

        if (!$c.gus.cfIsAfterDate(dtFrom, dtTo)) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_048, ["오더기간 From", "오더기간 To"]);
            return false;
        }

        let diffObj = $c.gus.cfDifferBetween(dtFrom, dtTo);
        if (diffObj.year > 0 || diffObj.month > 0) {
            let confirmResult = await $c.win.confirm("오더기간 이 1개월이 넘습니다.조회하시겠습니까?");
            if (!confirmResult) {
                return false;
            }
        }
    } else {
        let chk = await $c.gus.cfValidate([ed_odrNo]);
        if (!chk) return;
    }

    let odrNoVal = ed_odrNo.getValue().replace(/\s*$/, '');
    let odrDtFromVal = dma_orderSearch.get("odrDtFrom").replace(/\s*$/, '');
    let odrDtToVal = dma_orderSearch.get("odrDtTo").replace(/\s*$/, '');

    $c.gus.cfDisableObjects([btnInsertRow, btnDeleteRow, btnUndoMark]);
    $c.gus.cfEnableBtnOnly([btnSave]);

    ds_odrCommWrkPath.removeAll();
    ds_ctrtWrkPath.removeAll();
    ds_odrWrkPathStep.removeAll();
    ds_ctrtWrkPathStep.removeAll();

    spa_totalRow.setValue(0);
    spa_totalRow2.setValue(0);

    ds_odrWrkPathStepDetail.removeAll();
    ds_odrWrkPathStepDetailTemp.removeAll();

    // TODO: ds_wrkPlClsCd.Reset() / ds_LkStepNo.Reset() - lookup DataSet 재조회

    dma_orderSearch.set("odrNo", odrNoVal);
    dma_orderSearch.set("odrDtFrom", odrDtFromVal);
    dma_orderSearch.set("odrDtTo", odrDtToVal);

    await $c.sbm.execute(sbm_retrieve);
};

scwin.f_FieldClear = function() {
    ed_odrNo.setValue("");
    ed_odrNo.setFocus();
};

scwin.f_RetrieveWorkStep = async function() {
    if (dma_searchWrkStep.get("ctrtWrkPathSeq") == "0" || dma_searchWrkStep.get("ctrtWrkPathSeq") == "") {
        return;
    }
    await $c.sbm.execute(sbm_searchWorkStep);
};

scwin.f_InsertRow = async function() {
    let curRow = ds_odrWrkPathStepDetail.getRowPosition();
    let v_tempSeq = Math.floor(parseInt(ds_odrWrkPathStepDetail.getCellData(curRow, "odrWrkStpSeq")) / 10) * 10;
    if (scwin.f_checkOdrWrkStpSeq(ds_odrWrkPathStepDetail, v_tempSeq)) {
        ds_odrWrkPathStepDetail.insertRow(curRow + 1);
        scwin.f_CopyDataRow(ds_odrWrkPathStepDetail, curRow, curRow + 1);
        scwin.f_checkWorkStepEditMode(curRow + 1);
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_055, ["작업단계"]);
        return;
    }
};

scwin.f_AddRow = function() {
    let curRow = ds_odrWrkPathStepDetail.getRowPosition();
    let v_tempSeq = Math.floor(parseInt(ds_odrWrkPathStepDetail.getCellData(curRow, "odrWrkStpSeq")) / 10) * 10;
    if (scwin.f_checkOdrWrkStpSeq(ds_odrWrkPathStepDetail, v_tempSeq)) {
        ds_odrWrkPathStepDetail.insertRow(ds_odrWrkPathStepDetail.getRowCount());
    }
    let newRow = ds_odrWrkPathStepDetail.getRowCount() - 1;
    scwin.f_CopyDataRow(ds_odrWrkPathStepDetail, newRow - 1, newRow);
    scwin.f_checkWorkStepEditMode(newRow);
};

scwin.f_DeleteRow = function() {
    let curRow = ds_odrWrkPathStepDetail.getRowPosition();
    ds_odrWrkPathStepDetail.removeRow(curRow);
    let newCurRow = ds_odrWrkPathStepDetail.getRowPosition();
    if (newCurRow >= 0) {
        let v_tempSeq = Math.floor(parseInt(ds_odrWrkPathStepDetail.getCellData(newCurRow, "odrWrkStpSeq")) / 10) * 10;
        scwin.f_refreshOdrWrkStpSeq(ds_odrWrkPathStepDetail, v_tempSeq);
        scwin.f_checkWorkStepEditMode(newCurRow);
    }
};

scwin.f_UndoRow = function() {
    let curRow = ds_odrWrkPathStepDetail.getRowPosition();
    ds_odrWrkPathStepDetail.undoRow(curRow);
    let v_tempSeq = Math.floor(parseInt(ds_odrWrkPathStepDetail.getCellData(curRow, "odrWrkStpSeq")) / 10) * 10;
    scwin.f_refreshOdrWrkStpSeq(ds_odrWrkPathStepDetail, v_tempSeq);
    scwin.f_checkWorkStepEditMode(curRow);
};

scwin.f_CopyDataRow = function(dataObject, sourceRow, targetRow) {
    let v_odrWrkStpSeq = parseInt(dataObject.getCellData(sourceRow, "odrWrkStpSeq"));
    let v_tempSeq = Math.floor(v_odrWrkStpSeq / 10) * 10;
    let colCount = dataObject.getColumnCount();
    for (let i = 0; i < colCount; i++) {
        let colId = dataObject.getColumnID(i);
        if (colId == "odrWrkStpSeq") {
            dataObject.setCellData(targetRow, colId, parseInt(dataObject.getCellData(sourceRow, colId)) + 1);
        } else if (colId == "wrkPlClsCd" || colId == "wrkStpCd"
            || colId == "dptWrkPlCd" || colId == "dptWrkPlNm"
            || colId == "arvWrkPlCd" || colId == "arvWrkPlNm"
            || colId == "wrkLobranCd" || colId == "wrkLobranNm"
            || colId == "wrkStDt" || colId == "wrkStHh"
            || colId == "wrkEndDt" || colId == "wrkEndHh"
            || colId == "internalSellLodeptCd" || colId == "internalSellLodeptNm"
            || colId == "bizDomCd" || colId == "completeYn") {
            // 빈값 유지
        } else if (colId == "selpchItemCd") {
            dataObject.setCellData(targetRow, colId, scwin.SELPCH_ITEM_CD_NOSELL);
        } else if (colId == "selpchItemNm") {
            dataObject.setCellData(targetRow, colId, "무매출");
        } else {
            dataObject.setCellData(targetRow, colId, dataObject.getCellData(sourceRow, colId));
        }
    }
    scwin.f_refreshOdrWrkStpSeq(dataObject, v_tempSeq);
};

scwin.f_checkOdrWrkStpSeq = function(dataObject, v_tempSeq) {
    for (let j = 0; j < dataObject.getRowCount(); j++) {
        let seqVal = parseInt(dataObject.getCellData(j, "odrWrkStpSeq"));
        let v_compSeq = seqVal - v_tempSeq;
        if (Math.floor(seqVal / 10) * 10 == v_tempSeq && v_compSeq >= 9) {
            return false;
        }
    }
    return true;
};

scwin.f_refreshOdrWrkStpSeq = function(dataObject, v_tempSeq) {
    for (let j = 0; j < dataObject.getRowCount(); j++) {
        let seqVal = parseInt(dataObject.getCellData(j, "odrWrkStpSeq"));
        let v_compSeq = seqVal - v_tempSeq;
        if (seqVal > v_tempSeq && v_compSeq > 0 && v_compSeq < 10) {
            if (j > 0) {
                dataObject.setCellData(j, "odrWrkStpSeq", parseInt(dataObject.getCellData(j - 1, "odrWrkStpSeq")) + 1);
            }
        }
    }
};

scwin.f_Update = function() {
    $c.gus.cfDisableBtnOnly([btnUpdate]);
    $c.gus.cfEnableBtnOnly([btnSave]);

    gr_odrCommWrkPath.setReadOnly("grid", false);
    gr_odrWrkPathStpDetail.setReadOnly("grid", false);

    if (ds_odrWrkPathStep.getRowCount() > 0) {
        gr_odrWrkPathStpDetail.setColumnProp("selpchItemNm", "readOnly", true);
        $c.gus.cfDisableBtnOnly([btnInsertRow, btnDeleteRow, btnUndoMark]);
    }

    gr_odrWrkPathStpDetail.setFocusedCell(ds_odrWrkPathStepDetail.getRowPosition(), "dptWrkPlNm");
    scwin.v_row = ds_odrWrkPathStepDetail.getRowPosition();
    scwin.v_colid = "dptWrkPlNm";

    let odrCommWrkPathRow = ds_odrCommWrkPath.getRowPosition();
    if (odrCommWrkPathRow >= 0 && btnUpdate.getDisabled()) {
        if (scwin.f_chkResultsConfirmationCommodity(odrCommWrkPathRow)) {
            gr_odrCommWrkPath.setReadOnly("grid", true);
            gr_odrWrkPathStpDetail.setReadOnly("grid", true);
            $c.gus.cfDisableBtnOnly([btnInsertRow, btnDeleteRow, btnUndoMark]);
        } else {
            gr_odrCommWrkPath.setReadOnly("grid", false);
            gr_odrWrkPathStpDetail.setReadOnly("grid", false);
            $c.gus.cfEnableBtnOnly([btnInsertRow, btnDeleteRow, btnUndoMark]);
        }
    }

    scwin.f_checkWorkStepEditMode(ds_odrWrkPathStepDetail.getRowPosition());
};

scwin.f_Save = async function() {
    for (let i = 0; i < ds_odrWrkPathStepDetail.getRowCount(); i++) {
        let wrkStDt = ds_odrWrkPathStepDetail.getCellData(i, "wrkStDt");
        let wrkStHh = ds_odrWrkPathStepDetail.getCellData(i, "wrkStHh");
        let wrkEndDt = ds_odrWrkPathStepDetail.getCellData(i, "wrkEndDt");
        let wrkEndHh = ds_odrWrkPathStepDetail.getCellData(i, "wrkEndHh");

        if ($c.gus.cfIsNull(wrkStDt)) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["작업시작일자"]);
            return false;
        }
        if ($c.gus.cfIsNull(wrkStHh)) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["작업시작시간"]);
            return false;
        }
        if ($c.gus.cfIsNull(wrkEndDt)) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["작업종료일자"]);
            return false;
        }
        if ($c.gus.cfIsNull(wrkEndHh)) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["작업종료시간"]);
            return false;
        }
    }

    if (ds_odrCommWrkPath.getRowCount() > 0) {
        let firstCtrtWrkPathSeq = parseInt(ds_odrCommWrkPath.getCellData(0, "ctrtWrkPathSeq"));
        if (firstCtrtWrkPathSeq <= 0) {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["작업경로"]);
            gr_odrCommWrkPath.setFocusedCell(0, "ctrtWrkPathSeq");
            return;
        }
    }

    for (let i = 0; i < ds_odrWrkPathStepDetail.getRowCount(); i++) {
        if (ds_odrWrkPathStepDetail.getCellData(i, "wrkPlClsCd").trim() == "" && i > 0) {
            if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd")))
                ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlCd"));
            if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "arvWrkPlCd")) && i + 1 < ds_odrWrkPathStepDetail.getRowCount())
                ds_odrWrkPathStepDetail.setCellData(i, "arvWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlCd"));
            if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "arvWrkPlNm")) && i + 1 < ds_odrWrkPathStepDetail.getRowCount())
                ds_odrWrkPathStepDetail.setCellData(i, "arvWrkPlNm", ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlNm"));
        }
    }

    let chkGrid = await $c.gus.cfValidate([gr_odrWrkPathStpDetail]);
    if (!chkGrid) return;

    for (let idx = 0; idx < ds_odrWrkPathStepDetail.getRowCount(); idx++) {
        if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(idx, "wrkPlClsCd").trim()) && $c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(idx, "dptWrkPlCd").trim())) {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["작업장"]);
            gr_odrWrkPathStpDetail.setFocusedCell(idx, "dptWrkPlNm");
            return false;
        }

        if (ds_odrWrkPathStepDetail.getCellData(idx, "selpchItemCd") != scwin.SELPCH_ITEM_CD_NOSELL) {
            if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(idx, "wrkLobranCd").trim())) {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["작업점소"]);
                gr_odrWrkPathStpDetail.setFocusedCell(idx, "wrkLobranNm");
                return false;
            }
            if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(idx, "internalSellLodeptCd").trim())) {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["매출귀속부서"]);
                gr_odrWrkPathStpDetail.setFocusedCell(idx, "internalSellLodeptNm");
                return false;
            }
        }
    }

    let chkAll = await $c.gus.cfValidate([gr_odrCommWrkPath, gr_odrWrkPathStpDetail]);
    if (!chkAll) return;

    // TODO: f_chkOdrWrkPathStep 로직 - 선택되지 않은 작업단계 삭제 등 복잡한 저장 전처리
    scwin.f_chkOdrWrkPathStep();

    let confirmResult = await $c.gus.cfConfirmMsg(MSG_CM_CRM_001, ["작업단계정보"]);
    if (confirmResult) {
        await $c.sbm.execute(sbm_save);
    }
};

scwin.f_validChk = async function() {
    let chk = await $c.gus.cfValidate([gr_odrCommWrkPath, gr_odrWrkPathStpDetail]);
    if (chk) {
        for (let idx = 0; idx < ds_odrCommWrkPath.getRowCount(); idx++) {
            if (parseInt(ds_odrCommWrkPath.getCellData(idx, "ctrtWrkPathSeq")) <= 0) {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["작업경로"]);
                return false;
            }
        }
        return true;
    } else {
        return false;
    }
};

scwin.f_openCommPopUpGrid = function(disGubun, row, pCode, pName, pClose, pAllSearch) {
    let rtnList = null;
    let chkValue = false;

    switch (disGubun) {
        case 1:
            rtnList = $c.gus.cfCommonPopUp('retrieveLogisDeptInfo_tpro', pName, pCode, pClose, null, null, null, null, "A,B", null, null, null, null, null, pAllSearch, "작업점소,점소코드/명", null, null);
            if (rtnList != null) {
                if (rtnList[0].trim() != "N/A") {
                    ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranCd", rtnList[0]);
                    ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranNm", rtnList[1]);
                    ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranNmOrg", rtnList[1]);
                }
                chkValue = true;
            } else {
                ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranCd", "");
                ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranNm", "");
                ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranNmOrg", "");
            }
            break;

        case 2:
            let pWrkPlClsCd = ds_odrWrkPathStepDetail.getCellData(row, "wrkPlClsCd").trim();
            let pWhere2 = pWrkPlClsCd;
            pCode = ds_odrWrkPathStepDetail.getCellData(row, "dptWrkPlCd");
            pName = ds_odrWrkPathStepDetail.getCellData(row, "dptWrkPlNm");

            rtnList = $c.gus.cfCommonPopUp('retrieveWrkPlInfo_tpro', pName, pCode, pClose, null, null, null, null, pWhere2, null, null, null, null, null, pAllSearch, "작업장,작업장코드/명", null, null);
            if (rtnList != null) {
                if (rtnList[0].trim() != "N/A") {
                    ds_odrWrkPathStepDetail.setCellData(row, "dptWrkPlCd", rtnList[0]);
                    ds_odrWrkPathStepDetail.setCellData(row, "dptWrkPlNm", rtnList[1]);
                    ds_odrWrkPathStepDetail.setCellData(row, "dptWrkPlNmOrg", rtnList[1]);
                }
                chkValue = true;
            } else {
                ds_odrWrkPathStepDetail.setCellData(row, "dptWrkPlCd", "");
                ds_odrWrkPathStepDetail.setCellData(row, "dptWrkPlNm", "");
                ds_odrWrkPathStepDetail.setCellData(row, "dptWrkPlNmOrg", "");
                ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranCd", "");
                ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranNm", "");
                ds_odrWrkPathStepDetail.setCellData(row, "wrkLobranNmOrg", "");
                ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptCd", "");
                ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptNm", "");
                ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptNmOrg", "");
            }
            break;

        case 3:
            let pWhere3 = "T,J,,,,T,1";
            rtnList = $c.gus.cfCommonPopUp('retrieveLogisDeptInfo_tpro', pName, pCode, pClose, null, null, null, null, pWhere3, null, null, null, null, null, pAllSearch, "매출귀속부서,부서코드/명", null, null);
            if (rtnList != null) {
                if (rtnList[0].trim() != "N/A") {
                    ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptCd", rtnList[0]);
                    ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptNm", rtnList[1]);
                    ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptNmOrg", rtnList[1]);
                }
                chkValue = true;
            } else {
                ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptCd", "");
                ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptNm", "");
                ds_odrWrkPathStepDetail.setCellData(row, "internalSellLodeptNmOrg", "");
            }
            break;

        case 5:
            let ctrtNo5 = ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "ctrtNo");
            let odrKndCd5 = ds_odrCommWrkPath.getCellData(ds_odrCommWrkPath.getRowPosition(), "odrKndCd");
            let pWhere5 = ctrtNo5 + "," + odrKndCd5;
            rtnList = $c.gus.cfCommonPopUp('retrieveCtrtWrkPath_tpro', pCode, pName, pClose, null, null, null, null, pWhere5, null, null, null, null, null, pAllSearch, "작업경로,작업경로명,작업경로명", null, null);
            if (rtnList != null) {
                if (rtnList[0].trim() != "N/A") {
                    ds_odrCommWrkPath.setCellData(row, "ctrtWrkPathSeq", rtnList[0]);
                    ds_odrCommWrkPath.setCellData(row, "ctrtWrkPathNm", rtnList[1]);
                }
                chkValue = true;
            } else {
                ds_odrCommWrkPath.setCellData(row, "ctrtWrkPathSeq", "");
                ds_odrCommWrkPath.setCellData(row, "ctrtWrkPathNm", "");
            }
            break;

        default:
            break;
    }

    scwin.f_copyTempDataSet();
    return chkValue;
};

scwin.f_setWorkPathStepDetail = async function() {
    scwin.wrkLobranCd = scwin.lobranCd;
    scwin.wrkLobranNm = scwin.lobranNm;

    if (scwin.userId == "040239") {
        scwin.internalSellLodeptCd = "4A5";
        scwin.internalSellLodeptNm = "인천제강운송";
    } else {
        if (ds_lobran.getRowCount() > 0) {
            scwin.internalSellLodeptCd = ds_lobran.getCellData(ds_lobran.getRowPosition(), "lobranCd");
            scwin.internalSellLodeptNm = ds_lobran.getCellData(ds_lobran.getRowPosition(), "lobranNm");
        }
    }
    scwin.wrkLobranCdRow = 0;

    let curPos = ds_odrCommWrkPath.getRowPosition();
    if (ds_odrWrkPathStep.getRowCount() > 0 && ds_odrCommWrkPath.getCellData(curPos, "ctrtWrkPathSeq") == ds_odrCommWrkPath.getOriginalCellData(curPos, "ctrtWrkPathSeq")) {
        scwin.f_setOdrWrkPathStepToWrkPathStepDetail();
    } else if (ds_ctrtWrkPathStep.getRowCount() > 0) {
        scwin.f_setCtrtWrkPathStepToWrkPathStepDetail();
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        return;
    }

    ds_odrWrkPathStepDetail.setRowPosition(0);

    $c.gus.cfEnableBtnOnly([btnInsertRow, btnDeleteRow, btnUndoMark]);
    scwin.f_checkWorkStepEditMode(ds_odrWrkPathStepDetail.getRowPosition());
};

scwin.f_setOdrWrkPathStepToWrkPathStepDetail = function() {
    // TODO: ImportData/ExportData 대응 - ds_odrWrkPathStep 데이터를 ds_odrWrkPathStepDetail로 복사
    for (let i = 0; i < ds_odrWrkPathStep.getRowCount(); i++) {
        ds_odrWrkPathStepDetail.insertRow(ds_odrWrkPathStepDetail.getRowCount());
        let newRow = ds_odrWrkPathStepDetail.getRowCount() - 1;
        let colCount = ds_odrWrkPathStep.getColumnCount();
        for (let c = 0; c < colCount; c++) {
            let colId = ds_odrWrkPathStep.getColumnID(c);
            try {
                ds_odrWrkPathStepDetail.setCellData(newRow, colId, ds_odrWrkPathStep.getCellData(i, colId));
            } catch(e) {}
        }
    }

    for (let i = 0; i < ds_odrWrkPathStepDetail.getRowCount(); i++) {
        if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "wrkPlClsCd").trim())) {
            ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlNm", "");
            ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlNmOrg", "");
        }
        if (ds_odrWrkPathStepDetail.getCellData(i, "selpchItemCd") == scwin.SELPCH_ITEM_CD_NOSELL) {
            ds_odrWrkPathStepDetail.setCellData(i, "wrkLobranCd", "");
            ds_odrWrkPathStepDetail.setCellData(i, "wrkLobranNm", "");
            ds_odrWrkPathStepDetail.setCellData(i, "internalSellLodeptCd", "");
            ds_odrWrkPathStepDetail.setCellData(i, "internalSellLodeptNm", "");
            ds_odrWrkPathStepDetail.setCellData(i, "internalSellLodeptNmOrg", "");
        }
    }
};

scwin.f_setCtrtWrkPathStepToWrkPathStepDetail = function() {
    let curPos = ds_odrCommWrkPath.getRowPosition();
    let wrkStDtVal = ds_odrCommWrkPath.getCellData(curPos, "wrkStDt");
    let wrkStHhVal = ds_odrCommWrkPath.getCellData(curPos, "wrkStHh");
    let wrkEndDtVal = ds_odrCommWrkPath.getCellData(curPos, "wrkEndDt");
    let wrkEndHhVal = ds_odrCommWrkPath.getCellData(curPos, "wrkEndHh");

    for (let i = 0; i < ds_ctrtWrkPathStep.getRowCount(); i++) {
        ds_odrWrkPathStepDetail.insertRow(ds_odrWrkPathStepDetail.getRowCount());
        let newRow = ds_odrWrkPathStepDetail.getRowCount() - 1;

        ds_odrWrkPathStepDetail.setCellData(newRow, "odrNo", ds_odrCommWrkPath.getCellData(curPos, "odrNo"));
        ds_odrWrkPathStepDetail.setCellData(newRow, "commSeq", ds_odrCommWrkPath.getCellData(curPos, "commSeq"));
        ds_odrWrkPathStepDetail.setCellData(newRow, "odrWrkPathSeq", ds_odrCommWrkPath.getCellData(curPos, "odrWrkPathSeq"));
        ds_odrWrkPathStepDetail.setCellData(newRow, "ctrtWrkPathSeq", ds_odrCommWrkPath.getCellData(curPos, "ctrtWrkPathSeq"));
        ds_odrWrkPathStepDetail.setCellData(newRow, "odrWrkPathNm", ds_ctrtWrkPathStep.getCellData(i, "ctrtWrkPathNm"));
        ds_odrWrkPathStepDetail.setCellData(newRow, "odrWrkStpSeq", ds_ctrtWrkPathStep.getCellData(i, "ctrtWrkStpSeq"));
        ds_odrWrkPathStepDetail.setCellData(newRow, "wrkPlClsCd", ds_ctrtWrkPathStep.getCellData(i, "wrkPlClsCd"));
        ds_odrWrkPathStepDetail.setCellData(newRow, "bizDomCd", ds_ctrtWrkPathStep.getCellData(i, "bizDomCd"));
        ds_odrWrkPathStepDetail.setCellData(newRow, "wrkStpCd", ds_ctrtWrkPathStep.getCellData(i, "wrkStpCd"));
        try { ds_odrWrkPathStepDetail.setCellData(newRow, "wrkStpNm", ds_ctrtWrkPathStep.getCellData(i, "wrkStpNm")); } catch(e) {}
        ds_odrWrkPathStepDetail.setCellData(newRow, "selpchItemCd", ds_ctrtWrkPathStep.getCellData(i, "selpchItemCd"));
        ds_odrWrkPathStepDetail.setCellData(newRow, "selpchItemNm", ds_ctrtWrkPathStep.getCellData(i, "selpchItemNm"));

        // TODO: 작업시작/종료 일시 계산 로직 (Date 연산)
        ds_odrWrkPathStepDetail.setCellData(newRow, "wrkStDt", wrkStDtVal);
        ds_odrWrkPathStepDetail.setCellData(newRow, "wrkStHh", wrkStHhVal);
        ds_odrWrkPathStepDetail.setCellData(newRow, "wrkEndDt", wrkEndDtVal);
        ds_odrWrkPathStepDetail.setCellData(newRow, "wrkEndHh", wrkEndHhVal);

        try {
            ds_odrWrkPathStepDetail.setCellData(newRow, "vsslCd", ds_ctrtWrkPathStep.getCellData(i, "vsslCd"));
            ds_odrWrkPathStepDetail.setCellData(newRow, "vsslNm", ds_ctrtWrkPathStep.getCellData(i, "vsslNm"));
            ds_odrWrkPathStepDetail.setCellData(newRow, "portcnt", ds_ctrtWrkPathStep.getCellData(i, "portcnt"));
        } catch(e) {}
    }

    scwin.f_setOdrWrkPathStepDptArv();
    scwin.f_setWorkStepInfoRefresh();
};

