scwin.ds_odrWrkPathStepDetail_onrowpositionchange = function(info) {
    let row = info.row;
    if (row < 0) return;

    scwin.f_checkWorkStepEditMode(row);

    if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(row, "wrkPlClsCd").trim())) {
        gr_odrWrkPathStpDetail.setColumnProp("dptWrkPlNm", "readOnly", true);
    } else {
        gr_odrWrkPathStpDetail.setColumnProp("dptWrkPlNm", "readOnly", false);
    }

    if (ds_odrWrkPathStepDetail.getCellData(row, "selpchItemCd").trim() == scwin.SELPCH_ITEM_CD_NOSELL) {
        gr_odrWrkPathStpDetail.setColumnProp("wrkLobranNm", "readOnly", true);
        gr_odrWrkPathStpDetail.setColumnProp("internalSellLodeptNm", "readOnly", true);
    } else {
        gr_odrWrkPathStpDetail.setColumnProp("wrkLobranNm", "readOnly", false);
        gr_odrWrkPathStpDetail.setColumnProp("internalSellLodeptNm", "readOnly", false);
    }
};

scwin.lc_odrSearchGubun_onchange = function(e) {
    let v_index = lc_odrSearchGubun.getValue();

    if (v_index == "0") {
        // TODO: lay_odrDt show, lay_odrNo hide
        dma_orderSearch.set("odrDtFrom", scwin.vCurDate);
        dma_orderSearch.set("odrDtTo", scwin.vCurDate);
        ed_odrNo.setValue("");
    } else {
        // TODO: lay_odrDt hide, lay_odrNo show
        dma_orderSearch.set("odrDtFrom", "");
        dma_orderSearch.set("odrDtTo", "");
    }
};

scwin.ed_odrNo_onkeydown = function(e) {
    if (e.keyCode == 13) {
        scwin.f_Retrieve();
    }
};

